const PROFILE_MEDIA_BUCKETS = ['background', 'journal-images', 'avatars'];
const PROFILE_MEDIA_EXTENSIONS = ['.jpg', '.jpeg', '.png', '.webp', '.gif', '.bmp', '.avif', '.svg'];
const PROFILE_MEDIA_LIMIT_DEFAULT = 5;
